1	import {useDrag} from "@use-gesture/react";
2	import {useTransformContext, vec} from "mafs";
3	import * as React from "react";
4	import invariant from "tiny-invariant";
5	
6	import {X, Y} from "../math";
7	import useGraphConfig from "../reducer/use-graph-config";
8	import {getCSSZoomFactor} from "../utils";
9	
10	import type {RefObject} from "react";
11	
12	/**
13	 * Code in this file is derived from
14	 * https://github.com/stevenpetryk/mafs/blob/4520319379a2cc2df8148d8baaef1f85db117103/src/interaction/useMovable.tsx#L20-L83
15	 * and copied here under the terms of the MIT license.
16	 *
17	 * Copyright 2021 Steven Petryk
18	 *
19	 * Permission is hereby granted, free of charge, to any person obtaining a copy
20	 * of this software and associated documentation files (the "Software"), to deal
21	 * in the Software without restriction, including without limitation the rights
22	 * to use, copy, modify, merge, publish, distribute, sublicense, and/or sell
23	 * copies of the Software, and to permit persons to whom the Software is
24	 * furnished to do so, subject to the following conditions:
25	 *
26	 * The above copyright notice and this permission notice shall be included in
27	 * all copies or substantial portions of the Software.
28	 */
29	
30	export type Params = {
31	    gestureTarget: RefObject<Element>;
32	    onMove: (point: vec.Vector2) => unknown;
33	    onDragStart?: () => unknown;
34	    onDragEnd?: () => unknown;
35	    point: vec.Vector2;
36	    constrainKeyboardMovement: KeyboardMovementConstraint;
37	};
38	
39	export type KeyboardMovementConstraint =
40	    // The function form of KeyboardMovementConstraint should be a "snap"
41	    // function that takes a target point to move near, and returns the closest
42	    // valid point. If the function form is used, useDraggable will search for
43	    // the valid destination that is closest to the current point in the
44	    // direction of the movement.
45	    | ((point: vec.Vector2) => vec.Vector2)
46	    // Alternatively, the movement can be constrained to specific
47	    // pre-determined points based on which key is pressed.
48	    | {
49	          left: vec.Vector2;
50	          right: vec.Vector2;
51	          up: vec.Vector2;
52	          down: vec.Vector2;
53	      };
54	
55	type DragState = {
56	    dragging: boolean;
57	};
58	
59	export function useDraggable(args: Params): DragState {
60	    const {
61	        gestureTarget: target,
62	        onMove,
63	        onDragStart,
64	        onDragEnd,
65	        point,
66	        constrainKeyboardMovement,
67	    } = args;
68	    const [dragging, setDragging] = React.useState(false);
69	    const {xSpan, ySpan} = useSpanContext();
70	    const {viewTransform, userTransform} = useTransformContext();
71	
72	    const inverseViewTransform = vec.matrixInvert(viewTransform);
73	    invariant(inverseViewTransform, "The view transform must be invertible.");
74	
75	    const inverseTransform = React.useMemo(
76	        () => getInverseTransform(userTransform),
77	        [userTransform],
78	    );
79	
80	    const pickup = React.useRef<vec.Vector2>([0, 0]);
81	    const dragStarted = React.useRef(false);
82	
83	    useDrag(
84	        (state) => {
85	            const {type, event} = state;
86	            event?.stopPropagation();
87	
88	            const isKeyboard = type.includes("key");
89	            if (isKeyboard) {
90	                invariant(event instanceof KeyboardEvent);
91	                event?.preventDefault();
92	
93	                // When a key is held down, we see multiple "keydown" events,
94	                // followed by a single "keyup" event.
95	                // For a single keypress, we only see a "keydown" event, no
96	                // "keyup".
97	                // We never want to process the keyup event as an intent to
98	                // move so we bail on further processing here.
99	                if (type === "keyup") {
100	                    return;
101	                }
102	
103	                if (typeof constrainKeyboardMovement === "object") {
104	                    const destination =
105	                        constrainKeyboardMovement[directionForKey[event.key]];
106	                    onMove(destination ?? point);
107	                    return;
108	                }
109	
110	                const {
111	                    direction: yDownDirection,
112	                    altKey,
113	                    ctrlKey,
114	                    metaKey,
115	                    shiftKey,
116	                } = state;
117	
118	                // eslint-disable-next-line no-restricted-syntax
119	                const direction = [
120	                    yDownDirection[X],
121	                    -yDownDirection[Y],
122	                ] as vec.Vector2;
123	
124	                // eslint-disable-next-line @typescript-eslint/strict-boolean-expressions
125	                const span = Math.abs(direction[X]) ? xSpan : ySpan;
126	
127	                let divisions = 50;
128	                if (altKey || metaKey) {
129	                    divisions = 200;
130	                }
131	                if (shiftKey && !ctrlKey) {
132	                    divisions = 10;
133	                }
134	
135	                const min = span / (divisions * 2);
136	                const tests = range(
137	                    span / divisions,
138	                    span / 2,
139	                    span / divisions,
140	                );
141	
142	                for (const dx of tests) {
143	                    // Transform the test back into the point's coordinate system
144	                    const testMovement = vec.scale(direction, dx);
145	                    const testPoint = constrainKeyboardMovement(
146	                        vec.transform(
147	                            vec.add(
148	                                vec.transform(point, userTransform),
149	                                testMovement,
150	                            ),
151	                            inverseTransform,
152	                        ),
153	                    );
154	
155	                    if (vec.dist(testPoint, point) > min) {
156	                        onMove(testPoint);
157	                        break;
158	                    }
159	                }
160	            } else {
161	                const {last, movement: pixelMovement, first} = state;
162	
163	                setDragging(!last);
164	
165	                // If the drag has ended, call the onDragEnd callback.
166	                // This is used to help prevent phantom clicks on iOS by
167	                // allowing graphs to update their state after the drag ends.
168	                if (last && onDragEnd) {
169	                    onDragEnd();
170	                }
171	
172	                if (first) {
173	                    pickup.current = vec.transform(point, userTransform);
174	                    dragStarted.current = false;
175	                }
176	                if (vec.mag(pixelMovement) === 0) {
177	                    return;
178	                }
179	                // Don't start a drag if no movement; a click with zero
180	                // movement should not set isCurrentlyDragging and block
181	                // subsequent click-to-add-point events.
182	                if (!dragStarted.current) {
183	                    dragStarted.current = true;
184	                    onDragStart?.();
185	                }
186	
187	                // Compensate for CSS zoom applied by mobile font scaling
