1	import {Plot, vec} from "mafs";
2	import * as React from "react";
3	
4	import {
5	    usePerseusI18n,
6	    type I18nContextType,
7	} from "../../../components/i18n-context";
8	import {X, Y} from "../math/coordinates";
9	import {actions} from "../reducer/interactive-graph-action";
10	import useGraphConfig from "../reducer/use-graph-config";
11	
12	import {usePointAriaLabel} from "./components/build-point-aria-label";
13	import {ClipToGraphBounds} from "./components/clip-to-graph-bounds";
14	import {MovablePoint} from "./components/movable-point";
15	import SRDescInSVG from "./components/sr-description-within-svg";
16	import {srFormatNumber} from "./screenreader-text";
17	
18	import type {PerseusStrings} from "../../../strings";
19	import type {
20	    AbsoluteValueGraphState,
21	    Dispatch,
22	    InteractiveGraphElementSuite,
23	    MafsGraphProps,
24	} from "../types";
25	import type {Coord} from "@khanacademy/perseus-core";
26	
27	export function renderAbsoluteValueGraph(
28	    state: AbsoluteValueGraphState,
29	    dispatch: Dispatch,
30	    i18n: I18nContextType,
31	): InteractiveGraphElementSuite {
32	    return {
33	        graph: <AbsoluteValueGraph graphState={state} dispatch={dispatch} />,
34	        interactiveElementsDescription: getAbsoluteValueDescription(
35	            state,
36	            i18n,
37	        ),
38	    };
39	}
40	
41	type AbsoluteValueGraphProps = MafsGraphProps<AbsoluteValueGraphState>;
42	
43	function AbsoluteValueGraph(props: AbsoluteValueGraphProps) {
44	    const {dispatch, graphState} = props;
45	    const {interactiveColor} = useGraphConfig();
46	    const i18n = usePerseusI18n();
47	    const id = React.useId();
48	    const descriptionId = id + "-description";
49	    const slopeDescriptionId = id + "-slope";
50	
51	    const {coords, pointLabels, snapStep} = graphState;
52	    const buildLabel = usePointAriaLabel(pointLabels);
53	
54	    // Cache last valid coefficients to protect against transient invalid
55	    // states that can occur mid-drag (e.g., both points on the same x).
56	    const coeffRef = React.useRef<AbsoluteValueCoefficients>({
57	        m: 1,
58	        h: 0,
59	        v: 0,
60	    });
61	    const coeffs = getAbsoluteValueCoefficients(coords);
62	    if (Number.isFinite(coeffs.m)) {
63	        coeffRef.current = coeffs;
64	    }
65	
66	    const {m, h, v} = coeffRef.current;
67	
68	    const {
69	        srAbsoluteValueGraph,
70	        srAbsoluteValueVertexPoint,
71	        srAbsoluteValueSecondPoint,
72	        srAbsoluteValueDescription: srDescription,
73	        srAbsoluteValueSlope,
74	    } = describeAbsoluteValueGraph(graphState, i18n);
75	
76	    return (
77	        <g aria-label={srAbsoluteValueGraph} aria-describedby={descriptionId}>
78	            <ClipToGraphBounds>
79	                <Plot.OfX
80	                    y={(x) => m * Math.abs(x - h) + v}
81	                    color={interactiveColor}
82	                    svgPathProps={{
83	                        "aria-hidden": true,
84	                    }}
85	                />
86	            </ClipToGraphBounds>
87	            {coords.map((coord, i) => (
88	                <MovablePoint
89	                    key={"point-" + i}
90	                    ariaLabel={
91	                        buildLabel(i, coord) ??
92	                        (i === 0
93	                            ? srAbsoluteValueVertexPoint
94	                            : srAbsoluteValueSecondPoint)
95	                    }
96	                    // The arm point (index 1) determines the slope, so it
97	                    // carries the slope description; the vertex (index 0)
98	                    // does not.
99	                    ariaDescribedBy={i === 1 ? slopeDescriptionId : undefined}
100	                    point={coord}
101	                    sequenceNumber={i + 1}
102	                    constrain={getAbsoluteValueKeyboardConstraint(
103	                        coords,
104	                        snapStep,
105	                        i,
106	                    )}
107	                    onMove={(destination) =>
108	                        dispatch(
109	                            actions.absoluteValue.movePoint(i, destination),
110	                        )
111	                    }
112	                />
113	            ))}
114	            <SRDescInSVG id={descriptionId}>{srDescription}</SRDescInSVG>
115	            <SRDescInSVG id={slopeDescriptionId}>
116	                {srAbsoluteValueSlope}
117	            </SRDescInSVG>
118	        </g>
119	    );
120	}
121	
122	export type AbsoluteValueCoefficients = {
123	    m: number;
124	    h: number;
125	    v: number;
126	};
127	
128	/**
129	 * Compute the coefficients [m, h, v] for f(x) = m * |x - h| + v from two
130	 * control points: p1 (vertex) and p2 (a point on one arm).
131	 */
132	export function getAbsoluteValueCoefficients(
133	    coords: ReadonlyArray<Coord>,
134	): AbsoluteValueCoefficients {
135	    const p1 = coords[0];
136	    const p2 = coords[1];
137	
138	    const denom = p2[X] - p1[X];
139	    const num = p2[Y] - p1[Y];
140	    let m = Math.abs(num / denom);
141	    if (p2[Y] < p1[Y]) {
142	        m = -m;
143	    }
144	
145	    return {m, h: p1[X], v: p1[Y]};
146	}
147	
148	/**
149	 * Keyboard constraint for absolute value control points.
150	 * Skips any horizontal position where both points would share the same x.
151	 */
152	export const getAbsoluteValueKeyboardConstraint = (
153	    coords: ReadonlyArray<Coord>,
154	    snapStep: vec.Vector2,
155	    pointIndex: number,
156	): {
157	    up: vec.Vector2;
158	    down: vec.Vector2;
159	    left: vec.Vector2;
160	    right: vec.Vector2;
161	} => {
162	    const coordToBeMoved = coords[pointIndex];
163	    const otherPoint = coords[1 - pointIndex];
164	
165	    const moveWithConstraint = (
166	        moveFunc: (coord: vec.Vector2) => vec.Vector2,
167	    ): vec.Vector2 => {
168	        let movedCoord = moveFunc(coordToBeMoved);
169	        if (movedCoord[X] === otherPoint[X]) {
170	            movedCoord = moveFunc(movedCoord);
171	        }
172	        return movedCoord;
173	    };
174	
175	    return {
176	        up: vec.add(coordToBeMoved, [0, snapStep[Y]]),
177	        down: vec.sub(coordToBeMoved, [0, snapStep[Y]]),
178	        left: moveWithConstraint((coord) => vec.sub(coord, [snapStep[X], 0])),
179	        right: moveWithConstraint((coord) => vec.add(coord, [snapStep[X], 0])),
180	    };
181	};
182	
183	function getAbsoluteValueDescription(
184	    state: AbsoluteValueGraphState,
185	    i18n: I18nContextType,
186	): string {
187	    const {strings} = i18n;
188	    const {coords} = state;
189	    const {locale} = i18n;
190	    const [p1, p2] = coords;
191	    const slope = getAbsoluteValueCoefficients(coords).m;
192	
193	    return strings.srInteractiveElements({
194	        elements: strings.srAbsoluteValueInteractiveElements({
195	            point1X: srFormatNumber(p1[X], locale),
196	            point1Y: srFormatNumber(p1[Y], locale),
197	            point2X: srFormatNumber(p2[X], locale),
198	            point2Y: srFormatNumber(p2[Y], locale),
199	            slope: srFormatNumber(slope, locale),
200	        }),
201	    });
202	}
203	
204	function describeAbsoluteValueGraph(
205	    state: AbsoluteValueGraphState,
206	    i18n: I18nContextType,
207	): Record<string, string> {
208	    const {strings, locale} = i18n;
209	    const {coords} = state;
210	    const [vertex, armPoint] = coords;
211	
212	    const coeffs = getAbsoluteValueCoefficients(coords);
213	
